import { useEffect, useState } from "react";
import axiosInstance from "../axiosConfig";

const Tasks = () => {
  const [plans, setPlans] = useState([]);
  const [subscriptions, setSubscriptions] = useState([]);
  const [selectedPlan, setSelectedPlan] = useState("");
  const [loadingPlans, setLoadingPlans] = useState(false);
  const [loadingSubs, setLoadingSubs] = useState(false);

  const fetchPlans = async () => {
    try {
      setLoadingPlans(true);
      const res = await axiosInstance.get("/api/plans");
      setPlans(Array.isArray(res.data) ? res.data : []);
    } catch (error) {
      console.error(error);
      alert("Failed to load plans");
    } finally {
      setLoadingPlans(false);
    }
  };

  const fetchSubscriptions = async () => {
    try {
      setLoadingSubs(true);
      const res = await axiosInstance.get("/api/subscriptions");
      setSubscriptions(Array.isArray(res.data) ? res.data : []);
    } catch (error) {
      console.error(error);
      alert("Failed to load subscriptions");
    } finally {
      setLoadingSubs(false);
    }
  };

  const handleSubscribe = async () => {
    if (!selectedPlan) {
      return alert("Please select a plan");
    }

    try {
      await axiosInstance.post("/api/subscriptions", {
        plan: selectedPlan,
      });

      fetchSubscriptions();
    } catch (error) {
      console.error(error);
      alert("Subscription failed");
    }
  };

  const handleDelete = async (id) => {
    try {
      await axiosInstance.delete(`/api/subscriptions/${id}`);
      fetchSubscriptions();
    } catch (error) {
      console.error(error);
      alert("Failed to cancel subscription");
    }
  };

  useEffect(() => {
    fetchPlans();
    fetchSubscriptions();
  }, []);

  return (
    <div className="container">
      {/* HEADER */}
      <div className="mb-4">
        <h1 className="page-title">Subscriptions</h1>
        <p style={{ textAlign: "center", color: "#666" }}>
          Manage your active plans and subscriptions
        </p>
      </div>

      {/* PLAN SELECT CARD */}
      <div className="card">
        <h2 className="mb-4">Choose a Plan</h2>

        <select
          value={selectedPlan}
          onChange={(e) => setSelectedPlan(e.target.value)}
        >
          <option value="">Select a Plan</option>
          {plans.map((plan) => (
            <option key={plan._id} value={plan._id}>
              {plan.name} - ${plan.price}
            </option>
          ))}
        </select>

        {loadingPlans && <p>Loading plans...</p>}

        {!loadingPlans && plans.length === 0 && (
          <p style={{ color: "#ef4444" }}>
            No plans available. Contact admin.
          </p>
        )}

        <button
          onClick={handleSubscribe}
          className="btn-success mt-2"
          style={{ width: "100%" }}
        >
          Subscribe
        </button>
      </div>

      {/* SUBSCRIPTIONS */}
      <div className="mt-4">
        <h2 className="mb-4">My Subscriptions</h2>

        {loadingSubs && <p>Loading subscriptions...</p>}

        {!loadingSubs && subscriptions.length === 0 && (
          <p style={{ color: "#777" }}>No subscriptions yet</p>
        )}

        {subscriptions.map((sub) => (
          <div key={sub._id} className="card">
            <div className="flex">
              <div>
                <h3>{sub.plan?.name || "Unknown Plan"}</h3>
                <p style={{ color: "#666" }}>
                  Status:{" "}
                  <span style={{ fontWeight: "500" }}>
                    {sub.status}
                  </span>
                </p>
              </div>

              <button
                onClick={() => handleDelete(sub._id)}
                className="btn-danger"
              >
                Cancel
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Tasks;
